import React from 'react';
import './App.css';
import { Link, useNavigate } from 'react-router-dom'; 
import {BrowserRouter as Router, Route, Routes} from 'react-router-dom';

function App() {
    return (
        <Router>
            <Routes>
                <Route path="/" element={<Main_Page />}/> {/* Main_Page를 루트 경로에 렌더링 */}
                <Route path="diarypage" element={<Diarypage />}/> {/* Diarypage 경로 설정 */}
            </Routes>
        </Router>
    );
}
const Modal = ({ isOpen, onClose }) => { 


    // useNavigate는 컴포넌트 상단에서 호출해야 합니다
    const navigate = useNavigate();  // useNavigate 훅 호출

    // early return은 useNavigate 훅 호출 이후에 배치해야 함
    if (!isOpen) return null;  // isOpen이 false일 때 모달을 렌더링하지 않음

    function handleClick() {
        // navigate로 페이지 이동
        navigate('/diarypage');
    } 
    return (
        <div className='modal'>
            <ul className='modal_1'>
                <li>
                    {/* 클릭 시 navigate로 /diarypage로 이동 */}
                    <span onClick={handleClick}>잘자요</span> 
                </li>
                <li>
                    <Link to='/'>애칭 설정</Link>
                </li>
                <li>
                    <Link to='/'>Diray List</Link>
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
        </div>
    );
}

export default Modal;
